184	impl<W> WCodec<&StateAccept, &mut W> for Zenoh080
185	where
186	    W: Writer,
187	{
188	    type Output = Result<(), DidntWrite>;
189	
190	    fn write(self, writer: &mut W, x: &StateAccept) -> Self::Output {
191	        let mut count: usize = 0;
192	        let mut buff = vec![];
193	        let mut wbuf = buff.writer();
194	
195	        #[cfg(feature = "auth_pubkey")]
196	        {
197	            if let Some(pubkey) = x.pubkey.as_ref() {
198	                self.write(&mut wbuf, id::PUBKEY)?;
199	                self.write(&mut wbuf, pubkey)?;
200	                count += 1;
201	            }
202	        }
203	
204	        #[cfg(feature = "auth_usrpwd")]
205	        {
206	            if let Some(usrpwd) = x.usrpwd.as_ref() {
207	                self.write(&mut wbuf, id::USRPWD)?;
208	                self.write(&mut wbuf, usrpwd)?;
209	                count += 1;
210	            }
211	        }
212	
213	        self.write(&mut *writer, count)?;
214	        if !buff.is_empty() {
215	            let mut rbuf = buff.reader();
216	            rbuf.siphon(&mut *writer).map_err(|_| DidntWrite)?;
217	        }
218	
219	        Ok(())
220	    }
221	}
