223	impl<R> RCodec<StateAccept, &mut R> for Zenoh080
224	where
225	    R: Reader,
226	{
227	    type Error = DidntRead;
228	
229	    fn read(self, reader: &mut R) -> Result<StateAccept, Self::Error> {
230	        let mut count: usize = self.read(&mut *reader)?;
231	
232	        #[cfg(feature = "auth_pubkey")]
233	        let mut pubkey: Option<pubkey::StateAccept> = None;
234	        #[cfg(feature = "auth_usrpwd")]
235	        let mut usrpwd: Option<usrpwd::StateAccept> = None;
236	
237	        while count > 0 {
238	            let e: u8 = self.read(&mut *reader)?;
239	            match e {
240	                #[cfg(feature = "auth_pubkey")]
241	                id::PUBKEY => {
242	                    pubkey = Some(self.read(&mut *reader)?);
243	                }
244	                #[cfg(feature = "auth_usrpwd")]
245	                id::USRPWD => {
246	                    usrpwd = Some(self.read(&mut *reader)?);
247	                }
248	                _ => return Err(DidntRead),
249	            }
250	
251	            count -= 1;
252	        }
253	
254	        let state = StateAccept {
255	            #[cfg(feature = "auth_pubkey")]
256	            pubkey,
257	            #[cfg(feature = "auth_usrpwd")]
258	            usrpwd,
259	        };
260	        Ok(state)
261	    }
