51	impl AuthUsrPwd {
52	    pub fn new(credentials: Option<(User, Password)>) -> Self {
53	        Self {
54	            lookup: HashMap::new(),
55	            credentials,
56	        }
57	    }
58	
59	    pub async fn add_user(&mut self, user: User, password: Password) -> ZResult<()> {
60	        self.lookup.insert(user, password);
61	        Ok(())
62	    }
63	
64	    pub async fn del_user(&mut self, user: &User) -> ZResult<()> {
65	        self.lookup.remove(user);
66	        Ok(())
67	    }
