69	    pub async fn from_config(config: &UsrPwdConf) -> ZResult<Option<Self>> {
70	        const S: &str = "UsrPwd extension - From config.";
71	
72	        let mut lookup: HashMap<User, Password> = HashMap::new();
73	        if let Some(dict) = config.dictionary_file() {
74	            let content = tokio::fs::read_to_string(dict)
75	                .await
76	                .map_err(|e| zerror!("{S} Invalid user-password dictionary file: {}.", e))?;
77	
78	            // Populate the user-password dictionary
79	            // The config file is expected to be in the form of:
80	            //      usr1:pwd1
81	            //      usr2:pwd2
82	            //      usr3:pwd3
83	            // I.e.: one <user>:<password> entry per line
84	            for l in content.lines() {
85	                let line = l.trim();
86	                if line.is_empty() {
87	                    continue;
88	                }
89	                let idx = line.find(':').ok_or_else(|| {
90	                    zerror!("{S} Invalid user-password dictionary file: invalid format.")
91	                })?;
92	                let user = line[..idx].trim().as_bytes().to_owned();
93	                if user.is_empty() {
94	                    bail!("{S} Invalid user-password dictionary file: empty user.")
95	                }
96	                let password = line[idx + 1..].trim().as_bytes().to_owned();
97	                if password.is_empty() {
98	                    bail!("{S} Invalid user-password dictionary file: empty password.")
99	                }
100	                lookup.insert(user, password);
101	            }
102	            tracing::debug!("{S} User-password dictionary has been configured.");
103	        }
104	
105	        let mut credentials: Option<(User, Password)> = None;
106	        if let Some(user) = config.user() {
107	            if let Some(password) = config.password() {
108	                tracing::debug!("{S} User-password has been configured.");
109	                credentials = Some((user.as_bytes().to_owned(), password.as_bytes().to_owned()));
110	            }
111	        }
112	
113	        if !lookup.is_empty() || credentials.is_some() {
114	            tracing::debug!("{S} User-password authentication is enabled.");
115	            Ok(Some(Self {
116	                lookup,
117	                credentials,
118	            }))
119	        } else {
120	            Ok(None)
121	        }
122	    }
123	}
