128	            Some(c) => write!(
129	                f,
130	                "User: '{}', Password: '***', ",
131	                String::from_utf8_lossy(&c.0)
132	            )?,
133	            None => write!(f, "User: '', Password: '', ")?,
134	        }
135	        write!(f, "Dictionary: {{")?;
136	        for (i, (u, _)) in self.lookup.iter().enumerate() {
137	            if i != 0 {
138	                write!(f, ",")?;
139	            }
140	            write!(f, " {}", String::from_utf8_lossy(u))?;
141	        }
142	        write!(f, " }}")
143	    }
