217	/*************************************/
218	/*             OpenSyn               */
219	/*************************************/
220	/// ```text
221	///  7 6 5 4 3 2 1 0
222	/// +-+-+-+-+-+-+-+-+
223	/// ~     user      ~
224	/// +---------------+
225	/// ~     hash      ~
226	/// +---------------+
227	///
228	/// ZExtZBuf
229	/// ```
230	struct OpenSyn {
231	    user: Vec<u8>,
232	    hmac: Vec<u8>,
233	}
234	
235	impl<W> WCodec<&OpenSyn, &mut W> for Zenoh080
236	where
237	    W: Writer,
238	{
239	    type Output = Result<(), DidntWrite>;
240	
241	    fn write(self, writer: &mut W, x: &OpenSyn) -> Self::Output {
242	        self.write(&mut *writer, x.user.as_slice())?;
243	        self.write(&mut *writer, x.hmac.as_slice())?;
244	        Ok(())
245	    }
246	}
247	
248	impl<R> RCodec<OpenSyn, &mut R> for Zenoh080
249	where
250	    R: Reader,
251	{
252	    type Error = DidntRead;
253	
254	    fn read(self, reader: &mut R) -> Result<OpenSyn, Self::Error> {
255	        let user: Vec<u8> = self.read(&mut *reader)?;
256	        let hmac: Vec<u8> = self.read(&mut *reader)?;
257	        Ok(OpenSyn { user, hmac })
258	    }
259	}
260	
261	/*************************************/
262	/*             OpenAck               */
263	/*************************************/
264	/// ```text
265	///  7 6 5 4 3 2 1 0
266	/// +-+-+-+-+-+-+-+-+
267	/// +---------------+
268	///
269	/// ZExtUnit
270	/// ```
271	
272	#[async_trait]
273	impl<'a> OpenFsm for &'a AuthUsrPwdFsm<'a> {
274	    type Error = ZError;
275	
276	    type SendInitSynIn = &'a StateOpen;
277	    type SendInitSynOut = Option<ext::InitSyn>;
278	    async fn send_init_syn(
279	        self,
280	        _input: Self::SendInitSynIn,
281	    ) -> Result<Self::SendInitSynOut, Self::Error> {
282	        let output = zasyncread!(self.inner)
283	            .credentials
284	            .is_some()
285	            .then_some(ZExtUnit::new());
286	        Ok(output)
287	    }
288	
289	    type RecvInitAckIn = (&'a mut StateOpen, Option<ext::InitAck>);
290	    type RecvInitAckOut = ();
291	    async fn recv_init_ack(
292	        self,
293	        input: Self::RecvInitAckIn,
294	    ) -> Result<Self::RecvInitAckOut, Self::Error> {
295	        const S: &str = "UsrPwd extension - Recv InitSyn.";
296	
297	        if zasyncread!(self.inner).credentials.is_none() {
298	            return Ok(());
299	        };
300	
301	        let (state, mut ext_userwpd) = input;
302	        let ext_usrpwd = ext_userwpd
303	            .take()
304	            .ok_or_else(|| zerror!("{S} Decoding error."))?;
305	        state.nonce = ext_usrpwd.value;
306	
307	        Ok(())
308	    }
309	
310	    type SendOpenSynIn = &'a StateOpen;
311	    type SendOpenSynOut = Option<ext::OpenSyn>;
312	    async fn send_open_syn(
313	        self,
314	        state: Self::SendOpenSynIn,
315	    ) -> Result<Self::SendOpenSynOut, Self::Error> {
316	        const S: &str = "UsrPwd extension - Send OpenSyn.";
317	
318	        // If credentials are not configured, don't continue the USRPWD authentication
319	        let r_inner = zasyncread!(self.inner);
320	        let (user, password) = match r_inner.credentials.as_ref() {
321	            Some(cr) => cr,
322	            None => return Ok(None),
323	        };
324	
325	        // Create the HMAC of the password using the nonce received as a key (it's a challenge)
326	        let key = state.nonce.to_le_bytes();
327	        let hmac = hmac::sign(&key, password).map_err(|_| zerror!("{S} Encoding error."))?;
328	        // Create the OpenSyn extension
329	        let open_syn = OpenSyn {
330	            user: user.to_vec(),
331	            hmac,
332	        };
333	        drop(r_inner);
334	
335	        let codec = Zenoh080::new();
336	        let mut buff = vec![];
337	        let mut writer = buff.writer();
338	        codec
339	            .write(&mut writer, &open_syn)
340	            .map_err(|_| zerror!("{S} Encoding error."))?;
341	
342	        let output = Some(ZExtZBuf::new(buff.into()));
343	        Ok(output)
344	    }
345	
346	    type RecvOpenAckIn = (&'a mut StateOpen, Option<ext::OpenAck>);
347	    type RecvOpenAckOut = ();
348	    async fn recv_open_ack(
349	        self,
350	        input: Self::RecvOpenAckIn,
351	    ) -> Result<Self::RecvOpenAckOut, Self::Error> {
352	        const S: &str = "UsrPwd extension - Recv OpenAck.";
353	
354	        let (_, ext) = input;
355	        if zasyncread!(self.inner).credentials.is_some() && ext.is_none() {
356	            bail!("{S} Expected extension.");
357	        }
358	
359	        Ok(())
360	    }
361	}
362	
363	/*************************************/
364	/*            ACCEPT                 */
365	/*************************************/
366	#[async_trait]
367	impl<'a> AcceptFsm for &'a AuthUsrPwdFsm<'a> {
368	    type Error = ZError;
369	
370	    type RecvInitSynIn = (&'a mut StateAccept, Option<ext::InitSyn>);
371	    type RecvInitSynOut = ();
372	    async fn recv_init_syn(
373	        self,
374	        input: Self::RecvInitSynIn,
375	    ) -> Result<Self::RecvInitSynOut, Self::Error> {
376	        const S: &str = "UsrPwd extension - Recv InitSyn.";
377	
378	        let (_, ext_usrpwd) = input;
379	        if ext_usrpwd.is_none() {
380	            bail!("{S} Expected extension.");
381	        }
382	
383	        Ok(())
384	    }
385	
386	    type SendInitAckIn = &'a StateAccept;
387	    type SendInitAckOut = Option<ext::InitAck>;
388	    async fn send_init_ack(
389	        self,
390	        state: Self::SendInitAckIn,
391	    ) -> Result<Self::SendInitAckOut, Self::Error> {
392	        Ok(Some(ZExtZ64::new(state.nonce)))
393	    }
394	
395	    type RecvOpenSynIn = (&'a mut StateAccept, Option<ext::OpenSyn>);
396	    type RecvOpenSynOut = Vec<u8>; //value of userid is returned if recvopensynout is processed as valid
397	    async fn recv_open_syn(
398	        self,
399	        input: Self::RecvOpenSynIn,
400	    ) -> Result<Self::RecvOpenSynOut, Self::Error> {
401	        const S: &str = "UsrPwd extension - Recv OpenSyn.";
402	
403	        let (state, mut ext_usrpwd) = input;
404	        let ext_usrpwd = ext_usrpwd
405	            .take()
406	            .ok_or_else(|| zerror!("{S} Expected extension."))?;
407	
408	        let codec = Zenoh080::new();
409	        let mut reader = ext_usrpwd.value.reader();
410	        let open_syn: OpenSyn = codec
411	            .read(&mut reader)
412	            .map_err(|_| zerror!("{S} Decoding error."))?;
413	
414	        let r_inner = zasyncread!(self.inner);
415	        let pwd = r_inner
416	            .lookup
417	            .get(&open_syn.user)
418	            .ok_or_else(|| zerror!("{S} Invalid user."))?;
419	
420	        // Create the HMAC of the password using the nonce received as challenge
421	        let key = state.nonce.to_le_bytes();
422	        let hmac = hmac::sign(&key, pwd).map_err(|_| zerror!("{S} Encoding error."))?;
423	        if hmac != open_syn.hmac {
424	            bail!("{S} Invalid password.");
425	        }
426	        let username = open_syn.user.to_owned();
427	        Ok(username)
428	    }
429	
430	    type SendOpenAckIn = &'a StateAccept;
431	    type SendOpenAckOut = Option<ext::OpenAck>;
432	    async fn send_open_ack(
433	        self,
434	        _input: Self::SendOpenAckIn,
435	    ) -> Result<Self::SendOpenAckOut, Self::Error> {
436	        Ok(Some(ZExtUnit::new()))
437	    }
438	}
