441	    #[tokio::test(flavor = "multi_thread", worker_threads = 4)]
442	    async fn authenticator_usrpwd_config() {
443	        async fn inner() {
444	            use std::{fs::File, io::Write};
445	
446	            use zenoh_config::UsrPwdConf;
447	
448	            use super::AuthUsrPwd;
449	
450	            /* [CONFIG] */
451	            let f1 = "zenoh-test-auth-usrpwd.txt";
452	
453	            let mut config = UsrPwdConf::default();
454	            config.set_user(Some("usr1".to_owned())).unwrap();
455	            config.set_password(Some("pwd1".to_owned())).unwrap();
456	            config.set_dictionary_file(Some(f1.to_owned())).unwrap();
457	
458	            macro_rules! zconfig {
459	                () => {
460	                    File::options()
461	                        .create(true)
462	                        .write(true)
463	                        .truncate(true)
464	                        .open(f1)
465	                        .unwrap()
466	                };
467	            }
468	            // Valid config
469	            let mut c = zconfig!();
470	            writeln!(c, "usr1:pwd1").unwrap();
471	            drop(c);
472	            assert!(AuthUsrPwd::from_config(&config).await.unwrap().is_some());
473	            // Invalid config
474	            let mut c = zconfig!();
475	            writeln!(c, "usr1").unwrap();
476	            drop(c);
477	            assert!(AuthUsrPwd::from_config(&config).await.is_err());
478	            // Empty password
479	            let mut c = zconfig!();
480	            writeln!(c, "usr1:").unwrap();
481	            drop(c);
482	            assert!(AuthUsrPwd::from_config(&config).await.is_err());
483	            // Empty user
484	            let mut c = zconfig!();
485	            writeln!(c, ":pwd1").unwrap();
486	            drop(c);
487	            assert!(AuthUsrPwd::from_config(&config).await.is_err());
488	            // Empty user and password
489	            let mut c = zconfig!();
490	            writeln!(c, ":").unwrap();
491	            drop(c);
492	            assert!(AuthUsrPwd::from_config(&config).await.is_err());
493	
494	            let _ = std::fs::remove_file(f1);
495	        }
496	
497	        inner().await;
498	    }
499	}
