145	impl TransportLinkUnicastTx {
146	    pub(crate) async fn send_batch(
147	        &mut self,
148	        batch: &mut WBatch,
149	        priority: Option<Priority>,
150	    ) -> ZResult<()> {
151	        const ERR: &str = "Write error on link: ";
152	
153	        // tracing::trace!("WBatch: {:?}", batch);
154	
155	        let res = batch
156	            .finalize(self.buffer.as_mut())
157	            .map_err(|_| zerror!("{ERR}{self}"))?;
158	
159	        let bytes = match res {
160	            Finalize::Batch => batch.as_slice(),
161	            Finalize::Buffer => self
162	                .buffer
163	                .as_ref()
164	                .ok_or_else(|| zerror!("Invalid buffer finalization"))?
165	                .as_slice(),
166	        };
167	
168	        // tracing::trace!("WBytes: {:02x?}", bytes);
169	
170	        // Send the message on the link
171	        self.inner.link.write_all(bytes, priority).await?;
172	
173	        Ok(())
174	    }
175	
176	    pub(crate) async fn send(
177	        &mut self,
178	        msg: &TransportMessage,
179	        priority: Option<Priority>,
180	    ) -> ZResult<usize> {
181	        const ERR: &str = "Write error on link: ";
182	
183	        // Create the batch for serializing the message
184	        let mut batch = WBatch::new(self.inner.config.batch);
185	        batch.encode(msg).map_err(|_| zerror!("{ERR}{self}"))?;
186	        let len = batch.len() as usize;
187	        self.send_batch(&mut batch, priority).await?;
188	        Ok(len)
189	    }
190	}
