210	    pub(crate) link: LinkUnicast,
211	    pub(crate) config: TransportLinkUnicastConfig,
212	}
213	
214	impl TransportLinkUnicastRx {
215	    pub async fn recv_batch<C, T>(&mut self, buff: C, priority: Option<Priority>) -> ZResult<RBatch>
216	    where
217	        C: Fn() -> T + Copy,
218	        T: AsMut<[u8]> + ZSliceBuffer + 'static,
219	    {
220	        const ERR: &str = "Read error from link: ";
221	
222	        let mut into = (buff)();
223	        let end = if self.link.is_streamed() {
224	            // Read and decode the message length
225	            let mut len = BatchSize::MIN.to_le_bytes();
226	            self.link.read_exact(&mut len, priority).await?;
227	            let l = BatchSize::from_le_bytes(len) as usize;
228	
229	            // Read the bytes
230	            let slice = into
231	                .as_mut()
232	                .get_mut(len.len()..len.len() + l)
233	                .ok_or_else(|| zerror!("{ERR}{self}. Invalid batch length or buffer size."))?;
234	            self.link.read_exact(slice, priority).await?;
235	            len.len() + l
236	        } else {
237	            // Read the bytes
238	            self.link.read(into.as_mut(), priority).await?
239	        };
240	
241	        // tracing::trace!("RBytes: {:02x?}", &into.as_slice()[0..end]);
242	
243	        let buffer = ZSlice::new(Arc::new(into), 0, end)
244	            .map_err(|_| zerror!("{ERR}{self}. ZSlice index(es) out of bounds"))?;
245	        let mut batch = RBatch::new(self.config.batch, buffer);
246	        batch
247	            .initialize(buff)
248	            .map_err(|e| zerror!("{ERR}{self}. {e}."))?;
249	
250	        // tracing::trace!("RBatch: {:?}", batch);
251	
252	        Ok(batch)
253	    }
254	
255	    pub async fn recv(&mut self) -> ZResult<TransportMessage> {
256	        let mtu = self.config.batch.mtu as usize;
257	        let mut batch = self
258	            .recv_batch(|| zenoh_buffers::vec::uninit(mtu).into_boxed_slice(), None)
259	            .await?;
260	        let msg = batch
261	            .decode()
262	            .map_err(|_| zerror!("Decode error on link: {}", self))?;
263	        Ok(msg)
264	    }
265	}
