282	pub(crate) struct MaybeOpenAck {
283	    link: TransportLinkUnicastTx,
284	    open_ack: Option<OpenAck>,
285	}
286	
287	impl MaybeOpenAck {
288	    pub(crate) fn new(link: &TransportLinkUnicast, open_ack: Option<OpenAck>) -> Self {
289	        Self {
290	            link: link.tx(),
291	            open_ack,
292	        }
293	    }
294	
295	    pub(crate) async fn send_open_ack(mut self) -> ZResult<()> {
296	        if let Some(msg) = self.open_ack {
297	            zcondfeat!(
298	                "transport_compression",
299	                {
300	                    // !!! Workaround !!! as the state of the link is set with compression once the OpenSyn is received.
301	                    // Here we are disabling the compression just to send the OpenAck (that is not supposed to be compressed).
302	                    // Then then we re-enable it, in case it was enabled, after the OpenAck has been sent.
303	                    let compression = self.link.inner.config.batch.is_compression;
304	                    self.link.inner.config.batch.is_compression = false;
305	                    self.link.send(&msg.into(), None).await?;
306	                    self.link.inner.config.batch.is_compression = compression;
307	                },
308	                {
309	                    self.link.send(&msg.into(), None).await?;
310	                }
311	            )
312	        }
313	        Ok(())
314	    }
315	
316	    pub(crate) fn link(&self) -> Link {
317	        self.link.inner.link()
318	    }
319	}
