321	pub(crate) struct LinkUnicastWithOpenAck {
322	    pub(crate) link: TransportLinkUnicast,
323	    ack: Option<OpenAck>,
324	    pub(crate) associated_link: Option<TransportLinkUnicast>,
325	}
326	
327	impl LinkUnicastWithOpenAck {
328	    pub(crate) fn new(
329	        link: TransportLinkUnicast,
330	        ack: Option<OpenAck>,
331	        associated_link: Option<TransportLinkUnicast>,
332	    ) -> Self {
333	        Self {
334	            link,
335	            ack,
336	            associated_link,
337	        }
338	    }
339	
340	    pub(crate) fn inner_config(&self) -> &TransportLinkUnicastConfig {
341	        &self.link.config
342	    }
343	
344	    pub(crate) fn unpack(
345	        self,
346	    ) -> (
347	        TransportLinkUnicast,
348	        MaybeOpenAck,
349	        Option<TransportLinkUnicast>,
350	    ) {
351	        let ack = MaybeOpenAck::new(&self.link, self.ack);
352	        (self.link, ack, self.associated_link)
353	    }
354	
355	    pub(crate) fn fail(self) -> (TransportLinkUnicast, Option<TransportLinkUnicast>) {
356	        (self.link, self.associated_link)
357	    }
358	}
359	
