361	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
362	        match self.ack.as_ref() {
363	            Some(ack) => write!(f, "{}({:?})", self.link, ack),
364	            None => write!(f, "{}", self.link),
365	        }
366	    }
367	}
