186	        tracing::debug!("Closing multicast transport on {:?}", self.locator);
187	
188	        let callback = zwrite!(self.callback).take();
189	
190	        // Delete the transport on the manager
191	        let _ = self.manager.del_transport_multicast(&self.locator).await;
