335	    /*************************************/
336	    pub(super) fn new_peer(&self, locator: &Locator, join: Join) -> ZResult<()> {
337	        let mut link = Link::new_multicast(&self.get_link().link);
338	        link.dst = locator.clone();
339	
340	        let is_shm = zcondfeat!("shared-memory", join.ext_shm.is_some(), false);
341	        let peer = TransportPeer {
342	            zid: join.zid,
343	            whatami: join.whatami,
344	            is_qos: join.ext_qos.is_some(),
345	            #[cfg(feature = "shared-memory")]
346	            is_shm,
347	            links: vec![link],
348	            region_name: None, // TODO(regions): region names are unsupported for multicast transports
349	        };
350	
351	        let handler = match zread!(self.callback).as_ref() {
352	            Some(cb) => cb.new_peer(peer.clone())?,
353	            None => return Ok(()),
354	        };
355	
356	        // Build next SNs
357	        let next_sns = match join.ext_qos.as_ref() {
358	            Some(sns) => sns.to_vec(),
359	            None => vec![join.next_sn],
360	        }
361	        .into_boxed_slice();
362	
363	        let mut priority_rx = Vec::with_capacity(next_sns.len());
364	        for sn in next_sns.iter() {
365	            let tprx = TransportPriorityRx::make(
366	                join.resolution.get(Field::FrameSN),
367	                self.manager.config.defrag_buff_size,
368	            )?;
369	            tprx.sync(*sn)?;
370	            priority_rx.push(tprx);
371	        }
372	        let priority_rx = priority_rx.into_boxed_slice();
373	
374	        tracing::debug!(
375	                "New transport joined on {}: zid {}, whatami {}, resolution {:?}, locator {}, is_qos {}, is_shm {}, initial sn: {:?}",
376	                self.locator,
377	                peer.zid,
378	                peer.whatami,
379	                join.resolution,
380	                locator,
381	                peer.is_qos,
382	                is_shm,
383	                next_sns,
384	            );
385	
386	        // Create lease event
387	        // TODO(yuyuan): refine the clone behaviors
388	        let is_active = Arc::new(AtomicBool::new(false));
389	        let c_is_active = is_active.clone();
390	        let token = self.task_controller.get_cancellation_token();
391	        let c_token = token.clone();
392	        let c_self = self.clone();
393	        let c_locator = locator.clone();
394	        let task = async move {
395	            let mut interval =
396	                tokio::time::interval_at(tokio::time::Instant::now() + join.lease, join.lease);
397	            loop {
398	                tokio::select! {
399	                    _ = interval.tick() => {
400	                        if !c_is_active.swap(false, Ordering::AcqRel) {
401	                            break
402	                        }
403	                    }
404	                    _ = c_token.cancelled() => break
405	                }
406	            }
407	            let _ = c_self.del_peer(&c_locator, close::reason::EXPIRED);
408	        };
409	
410	        self.task_controller
411	            .spawn_with_rt(zenoh_runtime::ZRuntime::Acceptor, task);
412	
413	        // TODO(yuyuan): Integrate the above async task into TransportMulticastPeer
414	        // Store the new peer
415	        let peer = TransportMulticastPeer {
416	            version: join.version,
417	            locator: locator.clone(),
418	            zid: peer.zid,
419	            whatami: peer.whatami,
420	            resolution: join.resolution,
421	            lease: join.lease,
422	            is_active,
423	            token,
424	            priority_rx,
425	            handler,
426	            patch: min(PatchType::CURRENT, join.ext_patch),
427	            #[cfg(feature = "stats")]
428	            stats: self
429	                .stats
430	                .peer_link_stats(peer.zid, peer.whatami, &self.link_stats),
431	        };
432	        zwrite!(self.peers).insert(locator.clone(), peer);
433	
434	        Ok(())
435	    }
436	
437	    pub(super) fn del_peer(&self, locator: &Locator, reason: u8) -> ZResult<()> {
438	        let mut guard = zwrite!(self.peers);
439	        if let Some(peer) = guard.remove(locator) {
440	            tracing::debug!(
441	                "Peer {}/{}/{} has left multicast {} with reason: {}",
442	                peer.zid,
443	                peer.whatami,
444	                locator,
445	                self.locator,
446	                reason
447	            );
448	
449	            // TODO(yuyuan): Unify the termination
450	            peer.token.cancel();
451	            drop(guard);
452	            peer.handler.closed();
453	        }
454	        Ok(())
455	    }
456	
457	    pub(super) fn get_peers(&self) -> Vec<TransportPeer> {
458	        zread!(self.peers)
459	            .values()
460	            .map(|p| {
461	                let mut link = Link::new_multicast(&self.get_link().link);
462	                link.dst = p.locator.clone();
463	
464	                TransportPeer {
465	                    zid: p.zid,
466	                    whatami: p.whatami,
467	                    is_qos: p.is_qos(),
468	                    #[cfg(feature = "shared-memory")]
469	                    is_shm: self.is_shm(),
470	                    links: vec![link],
471	                    region_name: None,
472	                }
473	            })
474	            .collect()
475	    }
476	}
