49	pub(crate) struct ClosableCallback {
50	    callback: OnceLock<Arc<dyn TransportPeerEventHandler>>,
51	    closed: AtomicBool,
52	}
53	
54	impl ClosableCallback {
55	    pub(crate) fn new() -> Self {
56	        ClosableCallback {
57	            callback: OnceLock::new(),
58	            closed: AtomicBool::new(false),
59	        }
60	    }
61	
62	    pub(crate) fn set(&self, cb: Arc<dyn TransportPeerEventHandler>) {
63	        let _ = self.callback.set(cb);
64	    }
65	
66	    pub(crate) fn get(&self) -> Option<&Arc<dyn TransportPeerEventHandler>> {
67	        self.callback
68	            .get()
69	            .filter(|_| !self.closed.load(Ordering::Relaxed))
70	    }
71	
72	    pub(crate) fn close(&self) -> Option<&Arc<dyn TransportPeerEventHandler>> {
73	        self.closed.store(true, Ordering::Relaxed);
74	        self.callback.get()
75	    }
