81	#[derive(Clone)]
82	pub(crate) struct TransportUnicastUniversal {
83	    // Transport Manager
84	    pub(crate) manager: Arc<TransportManager>,
85	    // Transport config
86	    pub(super) config: Arc<TransportConfigUnicast>,
87	    // Tx priorities
88	    pub(super) priority_tx: Arc<[TransportPriorityTx]>,
89	    // Rx priorities
90	    pub(super) priority_rx: Arc<[TransportPriorityRx]>,
91	    #[cfg(feature = "shared-memory")]
92	    pub(super) shm_context: Option<UnicastTransportShmContext>,
93	    // The links associated to the channel
94	    pub(super) links: Arc<RwLock<TransportLinks>>,
95	    // The callback
96	    pub(super) callback: Arc<ClosableCallback>,
97	    // Mutex for notification
98	    pub(super) status: Arc<AsyncMutex<TransportStatus>>,
99	    // Transport statistics
100	    #[cfg(feature = "stats")]
101	    pub(super) stats: zenoh_stats::TransportStats,
102	}
103	
104	impl TransportUnicastUniversal {
105	    pub fn make(
106	        manager: TransportManager,
107	        config: TransportConfigUnicast,
108	        #[cfg(feature = "shared-memory")] shm_context: Option<UnicastTransportShmContext>,
109	        #[cfg(feature = "stats")] stats: zenoh_stats::TransportStats,
110	    ) -> ZResult<Arc<dyn TransportUnicastTrait>> {
111	        let mut priority_tx = vec![];
112	        let mut priority_rx = vec![];
113	
114	        let num = if config.is_qos { Priority::NUM } else { 1 };
115	        for _ in 0..num {
116	            priority_tx.push(TransportPriorityTx::make(config.sn_resolution)?);
117	        }
118	
119	        for _ in 0..Priority::NUM {
120	            priority_rx.push(TransportPriorityRx::make(
121	                config.sn_resolution,
122	                manager.config.defrag_buff_size,
123	            )?);
124	        }
125	
126	        let initial_sn = PrioritySn {
127	            reliable: config.tx_initial_sn,
128	            best_effort: config.tx_initial_sn,
129	        };
130	        for c in priority_tx.iter() {
131	            c.sync(initial_sn)?;
132	        }
133	
134	        let t = Arc::new(TransportUnicastUniversal {
135	            manager: Arc::new(manager),
136	            config: Arc::new(config),
137	            priority_tx: priority_tx.into_boxed_slice().into(),
138	            priority_rx: priority_rx.into_boxed_slice().into(),
139	            links: Arc::new(RwLock::new(TransportLinks::default())),
140	            callback: Arc::new(ClosableCallback::new()),
141	            status: Arc::new(AsyncMutex::new(TransportStatus::Uninitialized)),
142	            #[cfg(feature = "stats")]
143	            stats,
144	            #[cfg(feature = "shared-memory")]
145	            shm_context,
146	        });
147	
148	        Ok(t)
149	    }
150	
151	    /*************************************/
152	    /*           TERMINATION             */
153	    /*************************************/
154	    pub(super) async fn delete(&self) -> ZResult<()> {
155	        tracing::debug!(
156	            "[{}] Closing transport with peer: {}",
157	            self.manager.config.zid,
158	            self.config.zid
159	        );
160	
161	        // Mark the transport as no longer alive and keep the lock
162	        // to avoid concurrent new_transport and closing/closed notifications
163	        let mut status_guard = self.get_status().await;
164	        *status_guard = TransportStatus::Closed;
165	        let callback = self.callback.close();
166	
167	        // Close all the links
168	        let mut links = zwrite!(self.links).take();
169	        for l in links.drain(..) {
170	            let _ = l.close().await;
171	        }
172	
173	        // Notify the callback that we have closed the transport
174	        if let Some(cb) = callback {
175	            cb.closed();
176	        }
177	        // Delete the transport on the manager - this should be the last step to ensure that no new transport to the same peer can be added while we are closing this transport.
178	        // We also drop the status_guard, to avoid deadlock due to different lock acquisition order in init_existing_transport unicast.
179	        // The lock is no longer needed at this point, as we have already marked the transport as not alive and taken the callback to notify it of the closure.
180	        drop(status_guard);
181	        let _ = self.manager.del_transport_unicast(&self.config.zid).await;
182	        Ok(())
183	    }
184	
185	    pub(crate) async fn del_link(&self, link: Link) -> ZResult<()> {
186	        // Try to remove the link
187	        let Some((is_last, stl, associated_link)) = zwrite!(self.links).remove_link(&link) else {
188	            bail!(
189	                "Can not delete Link {} with peer: {}",
190	                link,
191	                self.config.zid
192	            )
193	        };
194	
195	        // Notify the callback
196	        if let Some(callback) = self.callback.get().cloned() {
197	            let associated_link = associated_link.clone();
198	            tokio::task::spawn_blocking(move || {
199	                callback.del_link(link);
200	                if let Some(asl) = &associated_link {
201	                    callback.del_link(Link::new_unicast(
202	                        &asl.link.link,
203	                        asl.link.config.priorities.clone(),
204	                        asl.link.config.reliability,
205	                    ));
206	                }
207	            })
208	            .await?;
209	        }
210	
211	        // Associated link must also be closed. run both close calls, return whichever failed first
212	        let close_asl = async {
213	            match associated_link {
214	                Some(asl) => asl.close().await,
215	                None => Ok(()),
216	            }
217	        };
218	        let (close_stl_res, close_asl_res) = tokio::join!(stl.close(), close_asl);
219	
220	        if is_last {
221	            self.delete().await?;
222	        }
223	        close_stl_res.and(close_asl_res)
224	    }
225	
226	    async fn sync(
227	        &self,
228	        initial_sn_rx: TransportSn,
229	    ) -> ZResult<AsyncMutexGuard<'_, TransportStatus>> {
230	        // Mark the transport as alive and keep the lock
231	        // to avoid concurrent new_transport and closing/closed notifications
232	        let mut status_guard = zasynclock!(self.status);
233	
234	        match *status_guard {
235	            TransportStatus::Uninitialized => {
236	                let csn = PrioritySn {
237	                    reliable: initial_sn_rx,
238	                    best_effort: initial_sn_rx,
239	                };
240	                for c in self.priority_rx.iter() {
241	                    c.sync(csn)?;
242	                }
243	                *status_guard = TransportStatus::Alive;
244	                Ok(status_guard)
245	            }
246	            TransportStatus::Alive => Ok(status_guard),
247	            TransportStatus::Closed => {
248	                let e = zerror!("Transport with peer {} is closed", self.config.zid);
249	                tracing::trace!("{}", e);
250	                Err(e.into())
251	            }
252	        }
253	    }
254	}
255	
256	#[async_trait]
257	impl TransportUnicastTrait for TransportUnicastUniversal {
258	    /*************************************/
259	    /*               LINK                */
260	    /*************************************/
261	    async fn add_link(
262	        &self,
263	        link: LinkUnicastWithOpenAck,
264	        other_initial_sn: TransportSn,
265	        other_lease: Duration,
266	    ) -> AddLinkResult {
267	        // sync the RX sequence number
268	        let status_guard = match self.sync(other_initial_sn).await {
269	            Ok(status_guard) => status_guard,
270	            Err(e) => {
271	                tracing::error!(
272	                    "Error syncing transport with peer {}: {}",
273	                    self.config.zid,
274	                    e
275	                );
276	                let (l, asl) = link.fail();
277	                return Err((e, l, asl, close::reason::GENERIC));
278	            }
279	        };
280	
281	        let mut guard = zwrite!(self.links);
282	
283	        // Check if we can add more inbound links
284	        if let TransportLinkUnicastDirection::Inbound = link.inner_config().direction {
285	            let limit = zcondfeat!(
286	                "transport_multilink",
287	                match self.config.multilink {
288	                    Some(_) => self.manager.config.unicast.max_links,
289	                    None => 1,
290	                },
291	                1
292	            );
293	
294	            let count = guard.nb_links_multilink(TransportLinkUnicastDirection::Inbound);
295	            if count >= limit {
296	                let e = zerror!(
297	                    "Can not add Link {} with peer {}: max num of links reached ({}/{})",
298	                    link,
299	                    self.config.zid,
300	                    count,
301	                    limit
302	                );
303	                let (l, asl) = link.fail();
304	                return Err((e.into(), l, asl, close::reason::MAX_LINKS));
305	            }
306	        }
307	
308	        // Wrap the link
309	        let (link, ack, associated_link) = link.unpack();
310	        let (mut link, consumer) =
311	            TransportLinkUnicastUniversal::new(self, link, &self.priority_tx);
312	
313	        // Handle associated link (if mixed-reliability link)
314	        let al_with_consumer =
315	            associated_link.map(|l| TransportLinkUnicastUniversal::new(self, l, &self.priority_tx));
316	        let associated_link = al_with_consumer.as_ref().map(|(l, _)| l.clone());
317	        // Add the link to the channel
318	        guard.push_link(link.clone(), associated_link.clone());
319	
320	        drop(guard);
321	
322	        // create a callback to start the link
323	        let transport = self.clone();
324	        let start_tx = {
325	            let mut link = link.clone();
326	            let transport = transport.clone();
327	            Box::new(move || {
328	                // Start the TX loop
329	                let keep_alive = self.manager.config.unicast.lease
330	                    / self.manager.config.unicast.keep_alive as u32;
331	                link.start_tx(transport.clone(), consumer, keep_alive);
332	                if let Some((mut associated_link, al_consumer)) = al_with_consumer {
333	                    associated_link.start_tx(transport, al_consumer, keep_alive);
334	                }
335	            })
336	        };
337	
338	        let start_rx = Box::new(move || {
339	            // Start the RX loop
340	            link.start_rx(transport.clone(), other_lease);
341	            if let Some(mut associated_link) = associated_link {
342	                associated_link.start_rx(transport, other_lease);
343	            }
344	        });
345	
346	        Ok((start_tx, start_rx, ack, status_guard))
347	    }
348	
349	    /*************************************/
350	    /*            ACCESSORS              */
351	    /*************************************/
352	    fn set_callback(&self, callback: Arc<dyn TransportPeerEventHandler>) {
353	        self.callback.set(callback)
354	    }
355	
356	    async fn get_status(&self) -> AsyncMutexGuard<'_, TransportStatus> {
357	        zasynclock!(self.status)
358	    }
359	
360	    fn get_zid(&self) -> ZenohIdProto {
361	        self.config.zid
362	    }
363	
364	    fn get_whatami(&self) -> WhatAmI {
365	        self.config.whatami
366	    }
367	
368	    #[cfg(feature = "shared-memory")]
369	    fn is_shm(&self) -> bool {
370	        self.config.shm.is_some()
371	    }
372	
373	    fn is_qos(&self) -> bool {
374	        self.config.is_qos
375	    }
376	
377	    fn region_name(&self) -> Option<RegionName> {
378	        self.config.region_name.clone()
379	    }
380	
381	    fn get_bound(&self) -> Option<Bound> {
382	        self.config.bound
383	    }
384	
385	    fn get_callback(&self) -> Option<Arc<dyn TransportPeerEventHandler>> {
386	        self.callback.get().cloned()
387	    }
388	
389	    fn get_config(&self) -> &TransportConfigUnicast {
390	        &self.config
391	    }
392	
393	    #[cfg(feature = "stats")]
394	    fn stats(&self) -> zenoh_stats::TransportStats {
395	        self.stats.clone()
396	    }
397	
398	    /*************************************/
399	    /*           TERMINATION             */
400	    /*************************************/
401	    async fn close(&self, reason: u8) -> ZResult<()> {
402	        tracing::trace!("Closing transport with peer: {}", self.config.zid);
403	
404	        let mut pipelines = zread!(self.links)
405	            .get_links()
406	            .iter()
407	            .map(|sl| sl.pipeline.clone())
408	            .collect::<Vec<_>>();
409	        for p in pipelines.drain(..) {
410	            // Close message to be sent on all the links
411	            // session should always be true for user-triggered close. However, in case of
412	            // multiple links, it is safer to close all the links first. When no links are left,
413	            // the transport is then considered closed.
414	            let msg: TransportMessage = Close {
415	                reason,
416	                session: false,
417	            }
418	            .into();
419	
420	            p.push_transport_message(msg, Priority::Background);
421	        }
422	        // Terminate and clean up the transport
423	        self.delete().await
424	    }
425	
426	    fn get_links(&self) -> Vec<Link> {
427	        zread!(self.links)
428	            .get_links()
429	            .iter()
430	            .map(|l| l.link.link())
431	            .collect()
432	    }
433	
434	    fn get_auth_ids(&self) -> TransportAuthId {
435	        let mut transport_auth_id = TransportAuthId::new(self.get_zid());
436	        // Convert LinkUnicast auth ids to AuthId
437	        zread!(self.links)
438	            .get_links()
439	            .iter()
440	            .for_each(|l| transport_auth_id.push_link_auth_id(l.link.link.get_auth_id().clone()));
441	
442	        // Convert usrpwd auth id to AuthId
443	        #[cfg(feature = "auth_usrpwd")]
444	        transport_auth_id.set_username(&self.config.auth_id);
445	        transport_auth_id
446	    }
447	
448	    /*************************************/
449	    /*                TX                 */
450	    /*************************************/
451	    fn schedule(&self, msg: NetworkMessageMut) -> ZResult<bool> {
452	        self.internal_schedule(msg)
453	    }
454	
455	    fn add_debug_fields<'a, 'b: 'a, 'c>(
456	        &self,
457	        s: &'c mut DebugStruct<'a, 'b>,
458	    ) -> &'c mut DebugStruct<'a, 'b> {
459	        s.field("sn_resolution", &self.config.sn_resolution)
460	    }
461	}
462	
463	/// Container for Transport links that manages link associations (namely for mixed-reliability).
464	/// Manages insertion/removal of links and their potential associated links while providing the
465	/// following:
466	/// - Evaluate multilink limit by considering each link association as a single link.
467	/// - Expose a read-only view on links that mixes associations in the same set (as if they were
468	///   separate links) for message scheduling based on QoS.
469	#[derive(Default)]
470	pub(super) struct TransportLinks {
471	    /// Two associated links are contiguous within the array as such:
472	    /// \[..., Link, AssociatedLink, ...\].
473	    ///
474	    /// This order is guaranteed at insertion, and assumed at removal.
475	    inner: Box<[TransportLinkMarker]>,
476	}
477	
478	impl TransportLinks {
479	    pub(super) fn get_links(&self) -> &[TransportLinkMarker] {
480	        &self.inner
481	    }
482	
483	    fn push_link(
484	        &mut self,
485	        link: TransportLinkUnicastUniversal,
486	        associated_link: Option<TransportLinkUnicastUniversal>,
487	    ) {
488	        let mut links =
489	            Vec::with_capacity(self.inner.len() + if associated_link.is_some() { 2 } else { 1 });
490	        links.extend_from_slice(&self.inner);
491	        links.push(TransportLinkMarker::Link(link));
492	
493	        if let Some(l) = associated_link {
494	            links.push(TransportLinkMarker::AssociatedLink(l));
495	        }
496	
497	        self.inner = links.into_boxed_slice();
498	    }
499	
500	    fn remove_link(
501	        &mut self,
502	        link: &Link,
503	    ) -> Option<(
504	        bool,
505	        TransportLinkUnicastUniversal,
506	        Option<TransportLinkUnicastUniversal>,
507	    )> {
508	        let link_equality = |tl: &TransportLinkUnicastUniversal, link: &Link| {
509	            // Compare LinkUnicast link to not compare TransportLinkUnicast direction
510	            Link::new_unicast(
511	                &tl.link.link,
512	                tl.link.config.priorities.clone(),
513	                tl.link.config.reliability,
514	            )
515	            .eq(link)
516	        };
517	        let index = self.inner.iter().position(|tl| link_equality(tl, link))?;
518	        let is_asl = matches!(self.inner[index], TransportLinkMarker::AssociatedLink(_));
519	
520	        let mut links = self.inner.to_vec();
521	
522	        // Remove the link
523	        let stl = links.remove(index);
524	
525	        // Remove associated link if applicable (also minding the array bounds)
526	        let asl = if is_asl {
527	            // Remove the link at index-1, which should NOT be an AssociatedLink variant
528	            index.checked_sub(1).map(|i| {
529	                let l = links.remove(i);
530	                debug_assert!(
531	                    matches!(l, TransportLinkMarker::AssociatedLink(_)).not(),
532	                    "should be the main link of the removed associated link"
533	                );
534	                l
535	            })
536	        } else {
537	            // Remove the link at index+1 (which is now at index after removal of the main link) IF it is an AssociatedLink
538	            if let Some(l) = links.get(index) {
539	                match l {
540	                    TransportLinkMarker::Link(_) => None,
541	                    TransportLinkMarker::AssociatedLink(_) => Some(links.remove(index)),
542	                }
543	            } else {
544	                None
545	            }
546	        };
547	
548	        self.inner = links.into_boxed_slice();
549	        Some((
550	            self.inner.is_empty(),
551	            stl.into_inner(),
552	            asl.map(TransportLinkMarker::into_inner),
553	        ))
554	    }
555	
556	    fn take(&mut self) -> Vec<TransportLinkUnicastUniversal> {
557	        std::mem::take(&mut self.inner)
558	            .into_vec()
559	            .into_iter()
560	            .map(TransportLinkMarker::into_inner)
561	            .collect()
562	    }
563	
564	    fn nb_links_multilink(&self, direction: TransportLinkUnicastDirection) -> usize {
565	        // Do not count AssociatedLink: pairs of (Link, AssociatedLink) must count as only one for
566	        // multilink limit.
567	        self.inner
568	            .iter()
569	            .filter(|l| {
570	                matches!(l, TransportLinkMarker::Link(_)) && l.link.config.direction == direction
571	            })
572	            .count()
573	    }
574	}
575	
576	#[derive(Clone)]
577	pub(super) enum TransportLinkMarker {
578	    Link(TransportLinkUnicastUniversal),
579	    AssociatedLink(TransportLinkUnicastUniversal),
580	}
581	
582	impl TransportLinkMarker {
583	    fn into_inner(self) -> TransportLinkUnicastUniversal {
584	        match self {
585	            TransportLinkMarker::Link(l) | TransportLinkMarker::AssociatedLink(l) => l,
586	        }
587	    }
588	}
589	
590	impl Deref for TransportLinkMarker {
591	    type Target = TransportLinkUnicastUniversal;
592	    #[inline]
593	    fn deref(&self) -> &Self::Target {
594	        match self {
595	            TransportLinkMarker::Link(l) => l,
596	            TransportLinkMarker::AssociatedLink(l) => l,
597	        }
598	    }
599	}
