326	        let compression = CompressionUnicastConf::default();
327	
328	        Self {
329	            lease: Duration::from_millis(*link_tx.lease()),
330	            keep_alive: *link_tx.keep_alive(),
331	            open_timeout: Duration::from_millis(*transport.open_timeout()),
332	            accept_timeout: Duration::from_millis(*transport.accept_timeout()),
333	            accept_pending: *transport.accept_pending(),
334	            max_sessions: *transport.max_sessions(),
335	            is_qos: *qos.enabled(),
336	            #[cfg(feature = "transport_multilink")]
337	            max_links: *transport.max_links(),
338	            #[cfg(feature = "transport_auth")]
339	            authenticator: Auth::default(),
340	            is_lowlatency: *transport.lowlatency(),
341	            #[cfg(feature = "transport_compression")]
342	            is_compression: *compression.enabled(),
343	        }
344	    }
