586	    pub(super) async fn init_new_transport_unicast(
587	        &self,
588	        config: TransportConfigUnicast,
589	        link: LinkUnicastWithOpenAck,
590	        other_initial_sn: TransportSn,
591	        other_lease: Duration,
592	        mut guard: AsyncMutexGuard<'_, HashMap<ZenohIdProto, Arc<dyn TransportUnicastTrait>>>,
593	    ) -> InitTransportResult {
594	        macro_rules! link_error {
595	            ($s:expr, $reason:expr) => {
596	                match $s {
597	                    Ok(output) => output,
598	                    Err(e) => {
599	                        let (l, asl) = link.fail();
600	                        return Err(InitTransportError::Link((e, l, asl, $reason)));
601	                    }
602	                }
603	            };
604	        }
605	
606	        // Verify that the node does not try to connect to itself
607	        if config.zid == self.zid() {
608	            let e = zerror!("{} Attempt to establish transport to itself", self.zid());
609	            tracing::warn!("{e}");
610	            let (l, asl) = link.fail();
611	            return Err(InitTransportError::Link((
612	                e.into(),
613	                l,
614	                asl,
615	                close::reason::CONNECTION_TO_SELF,
616	            )));
617	        }
618	
619	        // Verify that we haven't reached the transport number limit
620	        if guard.len() >= self.config.unicast.max_sessions {
621	            let e = zerror!(
622	                "Max transports reached ({}). Denying new transport with peer: {}",
623	                self.config.unicast.max_sessions,
624	                config.zid
625	            );
626	            tracing::trace!("{e}");
627	            let (l, asl) = link.fail();
628	            return Err(InitTransportError::Link((
629	                e.into(),
630	                l,
631	                asl,
632	                close::reason::INVALID,
633	            )));
634	        }
635	
636	        // Create the transport
637	        let is_multilink = zcondfeat!("transport_multilink", config.multilink.is_some(), false);
638	
639	        #[cfg(feature = "stats")]
640	        let stats = self.stats.unicast_transport_stats(
641	            config.zid,
642	            config.whatami,
643	            link.link
644	                .link
645	                .get_auth_id()
646	                .get_cert_common_name()
647	                .map(Into::into),
648	        );
649	
650	        #[cfg(feature = "shared-memory")]
651	        let shm_context = match &config.shm {
652	            Some(shm_config) => self.state.shm_context.as_ref().map(|context| {
653	                use zenoh_shm::api::protocol_implementations::posix::protocol_id::POSIX_PROTOCOL_ID;
654	
655	                use crate::{shm::PartnerShmConfig, shm_context::UnicastTransportShmContext};
656	
657	                let shm_provider = if shm_config.supports_protocol(POSIX_PROTOCOL_ID) {
658	                    context.shm_provider.clone()
659	                } else {
660	                    None
661	                };
662	
663	                UnicastTransportShmContext::new(
664	                    context.shm_reader.clone(),
665	                    shm_provider,
666	                    shm_config.clone(),
667	                )
668	            }),
669	            None => None,
670	        };
671	
672	        // Select and create transport implementation depending on the cfg and enabled features
673	        let t = if config.is_lowlatency {
674	            tracing::debug!("Will use LowLatency transport!");
675	            TransportUnicastLowlatency::make(
676	                self.clone(),
677	                config.clone(),
678	                #[cfg(feature = "shared-memory")]
679	                shm_context,
680	                #[cfg(feature = "stats")]
681	                stats,
682	            )
683	        } else {
684	            tracing::debug!("Will use Universal transport!");
685	            link_error!(
686	                TransportUnicastUniversal::make(
687	                    self.clone(),
688	                    config.clone(),
689	                    #[cfg(feature = "shared-memory")]
690	                    shm_context,
691	                    #[cfg(feature = "stats")]
692	                    stats
693	                ),
694	                close::reason::INVALID
695	            )
696	        };
697	
698	        // Add the link to the transport
699	        let (start_tx, start_rx, ack, add_link_guard) =
700	            match t.add_link(link, other_initial_sn, other_lease).await {
701	                Ok(val) => val,
702	                Err(e) => {
703	                    let _ = t.close(e.3).await;
704	                    return Err(InitTransportError::Link(e));
705	                }
706	            };
707	
708	        macro_rules! transport_error {
709	            ($s:expr, $reason:expr) => {
710	                match $s {
711	                    Ok(output) => output,
712	                    Err(e) => {
713	                        return Err(InitTransportError::Transport((e, t.clone(), $reason)));
714	                    }
715	                }
716	            };
717	        }
718	
719	        // Complete establish procedure
720	        let c_link = ack.link();
721	        transport_error!(ack.send_open_ack().await, close::reason::GENERIC);
722	
723	        // Add the transport transport to the list of active transports
724	        guard.insert(config.zid, t.clone());
725	        drop(guard);
726	
727	        start_tx();
728	
729	        // Notify manager's interface that there is a new transport
730	        transport_error!(
731	            self.notify_new_transport_unicast(&t),
732	            close::reason::GENERIC
733	        );
734	
735	        // Notify transport's callback interface that there is a new link
736	        transport_error!(
737	            Self::notify_new_link_unicast(&t, c_link).await,
738	            close::reason::GENERIC
739	        );
740	
741	        start_rx();
742	
743	        drop(add_link_guard);
744	
745	        zcondfeat!(
746	            "shared-memory",
747	            {
748	                tracing::debug!(
749	            "New transport opened between {} and {} - whatami: {}, sn resolution: {:?}, initial sn: {:?}, qos: {}, shm: {:?}, multilink: {}, lowlatency: {}",
750	            self.config.zid,
751	            config.zid,
752	            config.whatami,
753	            config.sn_resolution,
754	            config.tx_initial_sn,
755	            config.is_qos,
756	            config.shm,
757	            is_multilink,
758	            config.is_lowlatency
759	        );
760	            },
761	            {
762	                tracing::debug!(
763	            "New transport opened between {} and {} - whatami: {}, sn resolution: {:?}, initial sn: {:?}, qos: {:?}, multilink: {}, lowlatency: {}",
764	            self.config.zid,
765	            config.zid,
766	            config.whatami,
767	            config.sn_resolution,
768	            config.tx_initial_sn,
769	            config.is_qos,
770	            is_multilink,
771	            config.is_lowlatency
772	        );
773	            }
774	        );
775	
776	        Ok(t)
777	    }
