779	    pub(super) async fn init_transport_unicast(
780	        &self,
781	        config: TransportConfigUnicast,
782	        link: LinkUnicastWithOpenAck,
783	        other_initial_sn: TransportSn,
784	        other_lease: Duration,
785	    ) -> ZResult<TransportUnicast> {
786	        // First verify if the transport already exists
787	        let init_result = {
788	            let guard = zasynclock!(self.state.unicast.transports);
789	            match guard.get(&config.zid) {
790	                Some(transport) => {
791	                    let transport = transport.clone();
792	                    drop(guard);
793	                    self.init_existing_transport_unicast(
794	                        config,
795	                        link,
796	                        other_initial_sn,
797	                        other_lease,
798	                        transport,
799	                    )
800	                    .await
801	                }
802	                None => {
803	                    self.init_new_transport_unicast(
804	                        config,
805	                        link,
806	                        other_initial_sn,
807	                        other_lease,
808	                        guard,
809	                    )
810	                    .await
811	                }
812	            }
813	        };
814	
815	        match init_result {
816	            Ok(transport) => Ok(TransportUnicast(Arc::downgrade(&transport))),
817	            Err(InitTransportError::Link((e, link, associated_link, reason))) => {
818	                let _ = link.close(Some(reason)).await;
819	                if let Some(asl) = associated_link {
820	                    let _ = asl.close(Some(reason)).await;
821	                }
822	                Err(e)
823	            }
824	            Err(InitTransportError::Transport((e, transport, reason))) => {
825	                let _ = transport.close(reason).await;
826	                Err(e)
827	            }
828	        }
829	    }
