860	        // Automatically create a new link manager for the protocol if it does not exist
861	        let manager = self.new_link_manager_unicast(&endpoint).await?;
862	        // Fill and merge the endpoint configuration
863	        if let Some(config) = self
864	            .config
865	            .link_configs
866	            .get(&LinkKind::try_from(&endpoint)?)
867	        {
