926	    pub(crate) async fn handle_new_link_unicast(&self, link: LinkUnicast) {
927	        let incoming_counter = self.state.unicast.incoming.clone();
928	        if incoming_counter.load(SeqCst) >= self.config.unicast.accept_pending {
929	            // We reached the limit of concurrent incoming transport, this means two things:
930	            // - the values configured for ZN_OPEN_INCOMING_PENDING and ZN_OPEN_TIMEOUT
931	            //   are too small for the scenario zenoh is deployed in;
932	            // - there is a tentative of DoS attack.
933	            // In both cases, let's close the link straight away with no additional notification
934	            tracing::trace!("Closing link for preventing potential DoS: {}", link);
935	            let _ = link.close().await;
936	            return;
937	        }
938	
939	        // A new link is available
940	        tracing::trace!("Accepting link... {}", link);
941	        self.state.unicast.incoming.fetch_add(1, SeqCst);
942	
943	        // Spawn a task to accept the link
944	        let c_manager = self.clone();
945	        self.task_controller
946	            .spawn_with_rt(zenoh_runtime::ZRuntime::Acceptor, async move {
947	                if tokio::time::timeout(
948	                    c_manager.config.unicast.accept_timeout,
949	                    super::establishment::accept::accept_link(link, &c_manager),
950	                )
951	                .await
952	                .is_err()
953	                {
954	                    tracing::debug!(
955	                        "Failed to accept link before deadline ({}ms)",
956	                        c_manager.config.unicast.accept_timeout.as_millis()
957	                    );
958	                }
959	                incoming_counter.fetch_sub(1, SeqCst);
960	            });
961	    }
962	}
