84	            },
85	            queue_size: transport.manager.config.queue_size,
86	            wait_before_drop: transport.manager.config.wait_before_drop,
87	            max_wait_before_drop_fragments: transport.manager.config.max_wait_before_drop_fragments,
88	            wait_before_close: transport.manager.config.wait_before_close,
89	            batching_enabled: transport.manager.config.batching,
90	            batching_time_limit: transport.manager.config.queue_backoff,
91	            queue_alloc: transport.manager.config.queue_alloc,
92	        };
93	
94	        // The pipeline
95	        let (producer, consumer) =
96	            TransmissionPipeline::make(config, priority_tx, link.link.supports_priorities());
97	
98	        // Use the complete src and dest locators including parameters
99	        #[cfg(feature = "stats")]
100	        let link_unicast = link.link();
101	        #[cfg(feature = "stats")]
102	        let stats = transport
103	            .stats
104	            .link_stats(&link_unicast.src, &link_unicast.dst);
105	
106	        #[cfg(feature = "unstable")]
107	        let mut block_first_notifiers = Vec::new();
108	        #[cfg(feature = "unstable")]
109	        let mut block_first_waiters = Vec::new();
110	        #[cfg(feature = "unstable")]
111	        for _ in 0..Priority::NUM {
112	            let (notifier, waiter) = event::new();
113	            // notify to be make the BlockFirst "slot" available
114	            notifier.notify().unwrap();
115	            block_first_notifiers.push(notifier);
116	            block_first_waiters.push(waiter);
117	        }
118	
119	        let result = Self {
120	            link,
121	            pipeline: producer,
122	            task_controller: TaskController::default(),
123	            #[cfg(feature = "unstable")]
124	            block_first_notifiers: block_first_notifiers.try_into().ok().unwrap(),
125	            #[cfg(feature = "unstable")]
126	            block_first_waiters: block_first_waiters.try_into().ok().unwrap(),
127	            #[cfg(feature = "stats")]
128	            stats,
129	        };
