231	async fn tx_task(
232	    pipeline: TransmissionPipelineConsumer,
233	    link: &mut TransportLinkUnicastTx,
234	    keep_alive: Duration,
235	    cancellation_token: CancellationToken,
236	    #[cfg(feature = "stats")] stats: zenoh_stats::LinkStats,
237	) -> ZResult<()> {
238	    let keep_alive_tracker = TimeoutTracker::new(keep_alive);
239	    if link.inner.link.supports_priorities() {
240	        let (res, _, _) = select_all(pipeline.split().into_iter().map(|pipeline| {
241	            let mut link = link.clone();
242	            let cancellation_token = cancellation_token.clone();
243	            let keep_alive_tracker = keep_alive_tracker.clone();
244	            #[cfg(feature = "stats")]
245	            let stats = stats.clone();
246	            zenoh_runtime::ZRuntime::TX.spawn(async move {
247	                write_loop(
248	                    Some(pipeline.priority()),
249	                    pipeline,
250	                    &mut link,
251	                    keep_alive_tracker,
252	                    cancellation_token,
253	                    #[cfg(feature = "stats")]
254	                    stats,
255	                )
256	                .await
257	            })
258	        }))
259	        .await;
260	        res.unwrap()?;
261	    } else {
262	        write_loop(
263	            None,
264	            pipeline,
265	            link,
266	            keep_alive_tracker,
267	            cancellation_token,
268	            #[cfg(feature = "stats")]
269	            stats,
270	        )
271	        .await?;
272	    }
273	    Ok(())
274	}
