276	async fn write_loop(
277	    write_priority: Option<Priority>,
278	    mut pipeline: impl PipelineConsumer,
279	    link: &mut TransportLinkUnicastTx,
280	    keep_alive_tracker: TimeoutTracker,
281	    cancellation_token: CancellationToken,
282	    #[cfg(feature = "stats")] stats: zenoh_stats::LinkStats,
283	) -> ZResult<()> {
284	    let task = async {
285	        loop {
286	            tokio::select! {
287	                pull = pipeline.pull() => {
288	                    let Some((mut batch, priority)) = pull else {
289	                        // The queue has been disabled: break the tx loop, drain the queue, and exit
290	                        break
291	                    };
292	                    debug_assert!(write_priority.is_none() || write_priority == Some(priority));
293	                    link.send_batch(&mut batch, write_priority).await?;
294	                    // inform the latest message tracker that a message has been sent
295	                    keep_alive_tracker.reset();
296	
297	                    #[cfg(feature = "stats")]
298	                    {
299	                        stats.inc_bytes(zenoh_stats::Tx, batch.len() as u64);
300	                        stats.inc_transport_message(zenoh_stats::Tx, batch.stats.t_msgs as u64);
301	                    }
302	
303	                    // Reinsert the batch into the queue
304	                    pipeline.refill(batch, priority);
305	                },
306	                _ = keep_alive_tracker.wait_if(write_priority.unwrap_or(Priority::Control) == Priority::Control) => {
307	                    // A timeout occurred, no control/data messages have been sent during
308	                    // the keep_alive period, we need to send a KeepAlive message
309	                    let message: TransportMessage = KeepAlive.into();
310	
311	                    #[allow(unused_variables)] // Used when stats feature is enabled
312	                    let n = link.send(&message, Some(Priority::Control)).await?;
313	
314	                    #[cfg(feature = "stats")]
315	                    {
316	                        stats.inc_bytes(zenoh_stats::Tx, n as u64);
317	                        stats.inc_transport_message(zenoh_stats::Tx, 1);
318	                    }
319	                }
320	            }
321	        }
322	        ZResult::Ok(())
323	    };
324	    if let Some(result) = cancellation_token.run_until_cancelled(task).await {
325	        result?;
326	    }
327	
328	    // Drain the transmission pipeline and write remaining bytes on the wire
329	    let mut batches = pipeline.drain();
330	    for (mut b, _) in batches.drain(..) {
331	        tokio::time::timeout(
332	            keep_alive_tracker.timeout(),
333	            link.send_batch(&mut b, write_priority),
334	        )
335	        .await
336	        .map_err(|_| {
337	            zerror!(
338	                "{link}: flush failed after {} ms",
339	                keep_alive_tracker.timeout().as_millis()
340	            )
341	        })??;
342	
343	        #[cfg(feature = "stats")]
344	        {
345	            stats.inc_bytes(zenoh_stats::Tx, b.len() as u64);
346	            stats.inc_transport_message(zenoh_stats::Tx, b.stats.t_msgs as u64);
347	        }
348	    }
349	
350	    Ok(())
351	}
