353	async fn rx_task(
354	    link: &mut TransportLinkUnicastRx,
355	    transport: TransportUnicastUniversal,
356	    lease: Duration,
357	    rx_buffer_size: usize,
358	    cancellation_token: CancellationToken,
359	    #[cfg(feature = "stats")] stats: zenoh_stats::LinkStats,
360	) -> ZResult<()> {
361	    // The pool of buffers
362	    let mtu = link.config.batch.mtu as usize;
363	    let mut n = rx_buffer_size / mtu;
364	    if n == 0 {
365	        tracing::debug!("RX configured buffer of {rx_buffer_size} bytes is too small for {link} that has an MTU of {mtu} bytes. Defaulting to {mtu} bytes for RX buffer.");
366	        n = 1;
367	    }
368	    let pool = RecyclingObjectPool::new(n, move || vec![0_u8; mtu].into_boxed_slice());
369	
370	    let lease_tracker = TimeoutTracker::new(lease);
371	    if link.link.supports_priorities() {
372	        let (res, _, _) = select_all((Priority::MAX as u8..=Priority::MIN as u8).map(|prio| {
373	            let mut link = link.clone();
374	            let transport = transport.clone();
375	            let cancellation_token = cancellation_token.clone();
376	            let lease_tracker = lease_tracker.clone();
377	            #[cfg(feature = "stats")]
378	            let stats = stats.clone();
379	            let pool = pool.clone();
380	            zenoh_runtime::ZRuntime::RX.spawn(async move {
381	                cancellation_token
382	                    .run_until_cancelled(read_loop(
383	                        Some(Priority::try_from(prio).unwrap()),
384	                        &mut link,
385	                        transport,
386	                        lease_tracker,
387	                        #[cfg(feature = "stats")]
388	                        stats,
389	                        &pool,
390	                    ))
391	                    .await
392	            })
393	        }))
394	        .await;
395	        res.unwrap().transpose()?;
396	        Ok(())
397	    } else {
398	        read_loop(
399	            None,
400	            link,
401	            transport,
402	            lease_tracker,
403	            #[cfg(feature = "stats")]
404	            stats,
405	            &pool,
406	        )
407	        .await
408	    }
409	}
410	
411	async fn read_loop<F: Fn() -> Box<[u8]>>(
412	    priority: Option<Priority>,
413	    link: &mut TransportLinkUnicastRx,
414	    transport: TransportUnicastUniversal,
415	    lease_tracker: TimeoutTracker,
416	    #[cfg(feature = "stats")] stats: zenoh_stats::LinkStats,
417	    pool: &RecyclingObjectPool<Box<[u8]>, F>,
418	) -> ZResult<()> {
419	    async fn read<F: Fn() -> Box<[u8]>>(
420	        link: &mut TransportLinkUnicastRx,
421	        priority: Option<Priority>,
422	        pool: &RecyclingObjectPool<Box<[u8]>, F>,
423	    ) -> ZResult<RBatch> {
424	        let batch = link
425	            .recv_batch(|| pool.try_take().unwrap_or_else(|| pool.alloc()), priority)
426	            .await?;
427	        Ok(batch)
428	    }
429	
430	    let l = Link::new_unicast(
431	        &link.link,
432	        link.config.priorities.clone(),
433	        link.config.reliability,
434	    );
435	    loop {
436	        tokio::select! {
437	            batch = read(link, priority, pool) => {
438	                let batch = batch?;
439	                lease_tracker.reset();
440	                #[cfg(feature = "stats")]
441	                {
442	                    let header_bytes = if l.is_streamed { 2 } else { 0 };
443	                    stats.inc_bytes(zenoh_stats::Rx, header_bytes + batch.len() as u64);
444	                }
445	                transport.read_messages(batch, &l, #[cfg(feature = "stats")] &stats)?;
446	            }
447	            _ = lease_tracker.wait_if(priority.unwrap_or(Priority::Control) == Priority::Control) => {
448	                bail!("{link}: expired after {} milliseconds", lease_tracker.timeout().as_millis());
449	            }
450	        }
451	    }
452	}
453	
454	struct TimeoutTrackerInner {
455	    timeout: Duration,
456	    waker: AtomicWaker,
457	    has_timed_out: AtomicBool,
458	    latest_reset: Mutex<Instant>,
459	    task: OnceLock<JoinHandle<()>>,
460	}
461	
462	#[derive(Clone)]
463	struct TimeoutTracker(Arc<TimeoutTrackerInner>);
464	
465	impl TimeoutTracker {
466	    fn new(timeout: Duration) -> TimeoutTracker {
467	        let now = Instant::now();
468	        let inner = Arc::new(TimeoutTrackerInner {
469	            timeout,
470	            waker: AtomicWaker::new(),
471	            has_timed_out: AtomicBool::new(false),
472	            latest_reset: Mutex::new(now),
473	            task: OnceLock::new(),
474	        });
475	        let tracker = Arc::downgrade(&inner);
476	        let task = tokio::spawn(async move {
477	            let mut latest_reset = now;
478	            loop {
479	                tokio::time::sleep_until((latest_reset + timeout).into()).await;
480	                let prev = latest_reset;
481	                let Some(tracker) = tracker.upgrade() else {
482	                    break;
483	                };
484	                latest_reset = *tracker.latest_reset.lock().unwrap();
485	                if latest_reset <= prev {
486	                    latest_reset = Instant::now();
487	                    tracker.has_timed_out.store(true, Ordering::Release);
488	                    tracker.waker.wake();
489	                }
490	            }
491	        });
492	        inner.task.set(task).unwrap();
493	        Self(inner)
494	    }
495	
496	    fn timeout(&self) -> Duration {
497	        self.0.timeout
498	    }
499	
500	    fn reset(&self) {
501	        *self.0.latest_reset.lock().unwrap() = Instant::now();
502	    }
503	
504	    async fn wait_if(&self, predicate: bool) {
505	        poll_fn(|cx| {
506	            if !predicate {
507	                return Poll::Pending;
508	            }
509	            self.0.waker.register(cx.waker());
510	            if self.0.has_timed_out.load(Ordering::Acquire) {
511	                self.0.has_timed_out.store(false, Ordering::Release);
512	                return Poll::Ready(());
513	            }
514	            Poll::Pending
515	        })
516	        .await
517	    }
518	}
519	
520	impl Drop for TimeoutTracker {
521	    fn drop(&mut self) {
522	        self.0.task.get().unwrap().abort();
523	    }
524	}
525

